package com.jucheonsu.port.domain.portfolio.service;
import com.jucheonsu.port.domain.portfolio.dto.request.PortfolioCreateRequest;import com.jucheonsu.port.domain.portfolio.entity.Portfolio;import com.jucheonsu.port.domain.portfolio.repository.PortfolioRepository;import com.jucheonsu.port.domain.user.entity.User;import com.jucheonsu.port.domain.user.repository.UserRepository;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.InjectMocks;import org.mockito.Mock;import org.mockito.junit.jupiter.MockitoExtension;import java.util.Optional;import static org.assertj.core.api.Assertions.*;import static org.mockito.ArgumentMatchers.any;import static org.mockito.BDDMockito.*;
@ExtendWith(MockitoExtension.class)class PortfolioServiceImplTest{@Mock PortfolioRepository portfolioRepository;@Mock UserRepository userRepository;@InjectMocks PortfolioServiceImpl service;@Test void create_success(){User user=User.builder().email("a@a.com").name("A").build();Portfolio saved=Portfolio.builder().user(user).title("PORT").templateId("default").isPublic(true).build();given(userRepository.findByIdAndDeletedAtIsNull(1L)).willReturn(Optional.of(user));given(portfolioRepository.save(any(Portfolio.class))).willReturn(saved);var res=service.create(1L,new PortfolioCreateRequest("PORT","Backend","default",true));assertThat(res.title()).isEqualTo("PORT");}}
